import os
import sys
import subprocess
import tarfile
import zipfile

def create_backup(directory, format):
    if not os.path.isdir(directory):
        print("Invalid directory path.")
        return

    base_name = os.path.basename(os.path.normpath(directory))
    archive_name = f"{base_name}.{format}"
    
    if format == 'tar.gz':
        with tarfile.open(archive_name, 'w:gz') as tar:
            tar.add(directory, arcname=os.path.basename(directory))
    elif format == 'tar.bz2':
        with tarfile.open(archive_name, 'w:bz2') as tar:
            tar.add(directory, arcname=os.path.basename(directory))
    elif format == 'zip':
        with zipfile.ZipFile(archive_name, 'w', zipfile.ZIP_DEFLATED) as zipf:
            for root, dirs, files in os.walk(directory):
                for file in files:
                    zipf.write(os.path.join(root, file), 
                                os.path.relpath(os.path.join(root, file), 
                                os.path.join(directory, '..')))
    elif format == '7z':
        subprocess.run(['7z', 'a', archive_name, directory], check=True)
    else:
        print("Unsupported format. Use tar.gz, tar.bz2, zip, or 7z.")
        return

    print(f"Backup created: {archive_name}")

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python backup.py <directory_path> <format>")
    else:
        create_backup(sys.argv[1], sys.argv[2])